 1→'use client';
 2→
 3→import type { ElementType } from 'react';
 4→
 5→interface PageHeaderProps {
 6→  title: string;
 7→  description?: string;
 8→  action?: { label: string; onClick: () => void; icon?: ElementType };
 9→}
10→
11→export default function PageHeader({ title, description, action }: PageHeaderProps) {
12→  const Icon = action?.icon;
13→  return (
14→    <div className="flex items-center justify-between pb-6 mb-6 border-b border-[var(--border-subtle)]">
15→      <div>
16→        <h1 className="text-xl font-semibold text-[var(--text-primary)] tracking-tight">{title}</h1>
17→        {description && <p className="text-[13px] text-[var(--text-tertiary)] mt-0.5">{description}</p>}
18→      </div>
19→      {action && (
20→        <button
21→          onClick={action.onClick}
22→          className="inline-flex items-center gap-2 bg-[var(--accent)] text-white rounded-lg px-4 py-2 text-[13px] font-medium hover:bg-[var(--accent-hover)] transition-all duration-150 press-effect"
23→        >
24→          {Icon && <Icon className="w-4 h-4" />}
25→          {action.label}
26→        </button>
27→      )}
28→    </div>
29→  );
30→}
31→

